// Get all sheets and their viewport views, extract element counts per category per view
var sheets = new FilteredElementCollector(doc)
    .OfClass(typeof(ViewSheet))
    .Cast<ViewSheet>()
    .OrderBy(s => s.SheetNumber)
    .ToList();

var results = new List<object>();

// Target categories for QS
var categories = new[] {
    BuiltInCategory.OST_Walls,
    BuiltInCategory.OST_Doors,
    BuiltInCategory.OST_Windows,
    BuiltInCategory.OST_Floors,
    BuiltInCategory.OST_Roofs,
    BuiltInCategory.OST_Ceilings,
    BuiltInCategory.OST_Stairs,
    BuiltInCategory.OST_StructuralColumns,
    BuiltInCategory.OST_StructuralFraming,
    BuiltInCategory.OST_StructuralFoundation,
};

foreach (var sheet in sheets.Take(10)) // First 10 sheets as test
{
    var viewportIds = sheet.GetAllViewports();
    foreach (var vpId in viewportIds)
    {
        var vp = doc.GetElement(vpId) as Viewport;
        if (vp == null) continue;
        var view = doc.GetElement(vp.ViewId) as View;
        if (view == null || view is ViewSchedule) continue;

        var catCounts = new Dictionary<string, int>();
        foreach (var cat in categories)
        {
            try
            {
                var count = new FilteredElementCollector(doc, view.Id)
                    .OfCategory(cat)
                    .WhereElementIsNotElementType()
                    .GetElementCount();
                if (count > 0)
                    catCounts[cat.ToString()] = count;
            }
            catch { }
        }

        if (catCounts.Count > 0)
        {
            results.Add(new {
                sheet_number = sheet.SheetNumber,
                sheet_name = sheet.Name,
                view_name = view.Name,
                view_id = view.Id.IntegerValue,
                view_type = view.ViewType.ToString(),
                scale = view.Scale,
                element_counts = catCounts,
                total_elements = catCounts.Values.Sum()
            });
        }
    }
}

return results;

