                view_name = view.Name,
                view_id = view.Id.IntegerValue,
                view_type = view.ViewType.ToString(),
                scale = view.Scale,
                boq_items = boqItems,
                total_boq_items = boqItems.Count
            });
        }
    }
}

return new { total_views = results.Count, data = results };

